import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Paper,
  Alert,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import { useAuth } from "../contexts/AuthContext";

export default function Login() {
  const navigate = useNavigate();
  const { login } = useAuth();

  const [formData, setFormData] = useState({ mobile: "", otp: "" });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [otpSent, setOtpSent] = useState(false);

  const handleChange = (e) =>
    setFormData((p) => ({ ...p, [e.target.name]: e.target.value }));

  // ✅ Send OTP
  const handleSendOtp = async () => {
    setError("");
    if (!formData.mobile) {
      setError("Please enter a mobile number");
      return;
    }

    setLoading(true);
    try {
      const res = await axios.post("http://localhost:5000/api/otp/send", {
        phone: formData.mobile, // backend expects "phone"
      });

      if (res.data.success) {
        setOtpSent(true);
      } else {
        setError(res.data.message || "Failed to send OTP");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally {
      setLoading(false);
    }
  };

  // ✅ Verify OTP & Login
  const handleVerifyAndLogin = async (e) => {
    e.preventDefault();
    setError("");

    if (!otpSent) {
      setError("Please request OTP first");
      return;
    }

    if (!formData.otp) {
      setError("Please enter OTP");
      return;
    }

    setLoading(true);
    try {
      const res = await axios.post("http://localhost:5000/api/otp/verify", {
        phone: formData.mobile,
        otp: formData.otp,
      });

      if (res.data.success) {
        login(res.data.user); // save user in context
        navigate("/booking");
      } else {
        setError(res.data.message || "Invalid OTP");
      }
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography
          variant="h4"
          align="center"
          gutterBottom
          sx={{ color: "orangered" }}
        >
          Rider App
        </Typography>
        <Typography variant="body1" align="center" sx={{ mb: 3 }}>
          Login with OTP
        </Typography>

        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        <Box component="form" onSubmit={handleVerifyAndLogin}>
          {/* Mobile input (✅ no digit restriction now) */}
          <TextField
            fullWidth
            type="tel"
            label="Mobile Number"
            name="mobile"
            value={formData.mobile}
            onChange={handleChange}
            margin="normal"
            required
            disabled={otpSent}
          />

          {/* OTP input */}
          {otpSent && (
            <TextField
              fullWidth
              type="text"
              label="Enter OTP"
              name="otp"
              value={formData.otp}
              onChange={handleChange}
              margin="normal"
              inputProps={{ maxLength: 6 }}
              required
            />
          )}

          {/* Buttons */}
          {!otpSent ? (
            <Button
              type="button"
              fullWidth
              variant="contained"
              sx={{
                mt: 2,
                bgcolor: "orangered",
                "&:hover": { bgcolor: "darkred" },
              }}
              disabled={loading}
              onClick={handleSendOtp}
            >
              {loading ? (
                <CircularProgress size={24} sx={{ color: "white" }} />
              ) : (
                "Send OTP"
              )}
            </Button>
          ) : (
            <Button
              type="submit"
              fullWidth
              variant="contained"
              sx={{
                mt: 2,
                bgcolor: "orangered",
                "&:hover": { bgcolor: "darkred" },
              }}
              disabled={loading}
            >
              {loading ? (
                <CircularProgress size={24} sx={{ color: "white" }} />
              ) : (
                "Verify OTP & Login"
              )}
            </Button>
          )}
        </Box>

        <Typography align="center" sx={{ mt: 2 }}>
          Don’t have an account?{" "}
          <Button
            variant="text"
            onClick={() => navigate("/register")}
            sx={{ color: "orangered" }}
          >
            Sign Up
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
